module.exports = function roleMiddleware(requiredRole) {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Hiányzó azonosító token.' });
    }
    // allow passing an array of accepted roles or a single role
    if (Array.isArray(requiredRole)) {
      if (requiredRole.includes(req.user.role)) return next();
    } else {
      if (req.user.role === requiredRole) return next();
    }
    return res.status(403).json({ error: 'Nincs jogosultsága az erőforráshoz.' });
  };
};

const express = require('express');
const router = express.Router();
const categoryService = require('../services/categoryService');
const auth = require('../middlewares/authMiddleware');
const role = require('../middlewares/roleMiddleware');

router.get('/categories', (req, res) => {
  try {
    const categories = categoryService.findAll();
    res.status(200).json(categories);
  } catch (err) {
    res.status(err.status || 500).json({ error: err.message });
  }
});

router.get('/categories/:id', (req, res) => {
  try {
    const category = categoryService.findById(req.params.id);
    res.status(200).json(category);
  } catch (err) {
    res.status(err.status || 500).json({ error: err.message });
  }
});

router.post('/categories', auth, role('admin'), (req, res) => {
  try {
    const newCat = categoryService.create(req.body);
    res.status(201).json(newCat);
  } catch (err) {
    res.status(err.status || 500).json({ error: err.message });
  }
});

router.put('/categories/:id', auth, role('admin'), (req, res) => {
  try {
    const updated = categoryService.update(req.params.id, req.body);
    res.status(200).json(updated);
  } catch (err) {
    res.status(err.status || 500).json({ error: err.message });
  }
});

router.delete('/categories/:id', auth, role('admin'), (req, res) => {
  try {
    categoryService.delete(req.params.id);
    res.status(204).send();
  } catch (err) {
    res.status(err.status || 500).json({ error: err.message });
  }
});

module.exports = router;

const express = require('express');
const router = express.Router();
const recipeService = require('../services/recipeService');
const auth = require('../middlewares/authMiddleware');
const role = require('../middlewares/roleMiddleware');

router.get('/recipes', (req, res) => {
  try {
    const recipes = recipeService.findAll(req.query.category);
    res.status(200).json(recipes);
  } catch (err) {
    res.status(err.status || 500).json({ error: err.message });
  }
});

router.get('/recipes/:id', (req, res) => {
  try {
    const recipe = recipeService.findById(req.params.id);
    res.status(200).json(recipe);
  } catch (err) {
    res.status(err.status || 500).json({ error: err.message });
  }
});

router.post('/recipes', auth, role('admin'), (req, res) => {
  try {
    // the authenticated user is available at req.user
    const payload = { ...req.body, ownerId: req.user.id };
    const newRecipe = recipeService.create(payload);
    res.status(201).json(newRecipe);
  } catch (err) {
    res.status(err.status || 500).json({ error: err.message });
  }
});

router.put('/recipes/:id', auth, role('admin'), (req, res) => {
  try {
    const updated = recipeService.update(req.params.id, req.body);
    res.status(200).json(updated);
  } catch (err) {
    res.status(err.status || 500).json({ error: err.message });
  }
});

router.delete('/recipes/:id', auth, role('admin'), (req, res) => {
  try {
    recipeService.delete(req.params.id);
    res.status(204).send();
  } catch (err) {
    res.status(err.status || 500).json({ error: err.message });
  }
});

module.exports = router;

const ratingRepo = require('../repositories/ratingRepository');
const recipeRepo = require('../repositories/recipeRepository');

module.exports = {
  findAll() {
    return ratingRepo.findAll();
  },
  findById(id) {
    const rating = ratingRepo.findById(id);
    if (!rating) throw { status: 404, message: 'Értékelés nem található.' };
    return rating;
  },
  create(data) {
    if (!data.recipeId) {
      throw { status: 400, message: 'A recipeId kötelező.' };
    }
    const recipe = recipeRepo.findById(data.recipeId);
    if (!recipe) {
      throw { status: 400, message: 'A megadott recipeId nem létezik.' };
    }
    if (typeof data.score !== 'number' || !Number.isInteger(data.score) || data.score < 1 || data.score > 5) {
      throw { status: 400, message: 'A score 1–5 közötti egész szám lehet.' };
    }
    if (!data.userId) throw { status: 400, message: 'A userId kötelező.' };
    return ratingRepo.create(data);
  },

  update(id, data, actor) {
    if (data.score !== undefined) {
      if (typeof data.score !== 'number' || !Number.isInteger(data.score) || data.score < 1 || data.score > 5) {
        throw { status: 400, message: 'A score 1–5 közötti egész szám lehet.' };
      }
    }
    const existing = ratingRepo.findById(id);
    if (!existing) throw { status: 404, message: 'Értékelés nem található.' };
    // only owner can update (role-based checks removed)
    if (actor.id !== existing.userId) {
      throw { status: 403, message: 'Nincs jogosultsága módosítani ezt az értékelést.' };
    }
    const updated = ratingRepo.update(id, data);
    return updated;
  },
  delete(id, actor) {
    const existing = ratingRepo.findById(id);
    if (!existing) throw { status: 404, message: 'Értékelés nem található.' };
    // allow admin to delete any rating, otherwise only owner can delete
    if (actor.role !== 'admin' && actor.id !== existing.userId) {
      throw { status: 403, message: 'Nincs jogosultsága törölni ezt az értékelést.' };
    }
    const ok = ratingRepo.delete(id);
    if (!ok) throw { status: 404, message: 'Értékelés nem található.' };
    return true;
  },
  findByRecipeId(recipeId) {
    return ratingRepo.findByRecipeId(recipeId);
  },
  findByUserId(userId) {
    return ratingRepo.findByUserId(userId);
  }
};

